using Microsoft.EntityFrameworkCore;

class CosmosQuery
{
    async Task FindProducts(ProductContext ctx)
    {
        // Direct Cosmos SQL — c.Discriminator is preserved via HasDiscriminator("Discriminator") in OnModelCreating
        var sql = "SELECT * FROM c WHERE c.Discriminator = 'Product' AND c.Sku = @sku";
        // EF 9 Cosmos provider no longer supports sync I/O — use async equivalents
        var products = await ctx.Products.Where(p => p.Sku == "ABC").ToListAsync();
    }
}

